UPDATE service_todo
SET status = 'WAITING_CONFIRMATION',
    completed_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND case_id = #{caseId}
  AND status = 'OPEN'

UPDATE service_todo
SET status = 'COMPLETED',
    confirmed_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND case_id = #{caseId}
  AND status = 'WAITING_CONFIRMATION'
